// Package flashpack locates, extracts, and validates self-describing Jetson
// recovery artifacts. It accepts the existing untagged Thor schema v1 and the
// identity-safe T234 schema v2 generated by WendyOS Builder.
//
// Layout (see the builder script):
//
//	flashpack/
//	  manifest.json
//	  stage1/                         RCM-boot images (sent verbatim)
//	  stage2/out/flash_workspace/     FileToFlash.txt + signed partition images
//	  stage2/out/tools/               bootburn's sibling tools/ (ToolsVersion.txt …)
//	  stage2/bundle/unified_flash/…/bootburn   NVIDIA bootburn scripts
//	  stage2/pyyaml/                  pure-python PyYAML (+ LICENSE) bootburn imports
//
// Manifest is the authoritative definition of manifest.json: the builder script must
// emit exactly these fields. Fields are marked [consumed] (the flash logic depends
// on them) or [provenance] (recorded for humans inspecting the artifact; not read by
// code — keep them lean).
package flashpack

import (
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"os"
	"path/filepath"
	"strings"
)

// SupportedSchema is the newest tagged flashpack schema this wendy understands.
// The existing untagged Thor schema remains version 1; T234 is accepted only as
// tagged schema 2 because v1 has no target-identity contract.
const SupportedSchema = 2

const (
	FamilyT234              = "t234"
	T234Schema              = 2
	T234ProtocolMassStorage = "usb-mass-storage-v1"
	t234FlashPackageSize    = 128 << 20
)

// ErrNotInCache is returned by Resolve when no extracted tree or .tar.zst for the
// requested version is present in the cache. The caller may download the artifact
// to TarballCachePath and retry.
var ErrNotInCache = errors.New("flashpack not in cache")

// clearCacheHint is appended to integrity errors; the cached copy is untrusted and
// the user should discard it and re-fetch.
const clearCacheHint = "the cached flashpack is corrupt — clear it with `wendy cache clear` and re-run"

// FileMeta is one entry in the manifest's integrity map.
type FileMeta struct {
	SHA256 string `json:"sha256"`
	Size   int64  `json:"size"`
}

// RCMDownload is one boot-ROM download in a manifest-defined RCM phase.
type RCMDownload struct {
	Type string `json:"type"`
	File string `json:"file"`
}

// TargetIdentity is the exact unfused NVIDIA devkit a T234 flashpack targets.
// Both module and carrier identity are verified against device.json before the
// flash-package handoff (the first persistent/destructive operation).
type TargetIdentity struct {
	Device     string `json:"device"`
	Storage    string `json:"storage"`
	ModuleID   string `json:"module_id"`
	ModuleSKU  string `json:"module_sku"`
	CarrierID  string `json:"carrier_id"`
	CarrierSKU string `json:"carrier_sku"`
}

// Manifest is the parsed manifest.json (the authoritative schema — see package doc).
type Manifest struct {
	Schema         int            `json:"schema"` // [consumed] format version; checked against SupportedSchema
	Family         string         `json:"family,omitempty"`
	Protocol       string         `json:"protocol,omitempty"`
	USBProductID   string         `json:"usb_product_id,omitempty"`
	Target         TargetIdentity `json:"target,omitempty"`
	WendyOSVersion string         `json:"wendyos_version"` // [consumed] shown to the user
	DefaultMemBCT  string         `json:"default_membct"`  // [consumed] stage-1 membct filename (RAMCODE/2)

	// [consumed] stage-1 bootROM image filenames, in the exact order the bootROM
	// expects them. Driving this from data lets a future BSP reorder the chain
	// without a wendy code change. Empty falls back to the built-in default order.
	Stage1SendOrder []string        `json:"stage1_send_order"`
	RCMPhases       [][]RCMDownload `json:"rcm_phases,omitempty"`

	// [consumed] where the major trees live, relative to the flashpack root.
	Layout struct {
		Stage1             string `json:"stage1"`
		FlashWorkspace     string `json:"flash_workspace"`
		FlashPackageImage  string `json:"flash_package_image,omitempty"`
		FlashPackageStatus string `json:"flash_package_status,omitempty"`
		FlashPackageLogs   string `json:"flash_package_logs,omitempty"`
		FlashImages        string `json:"flash_images,omitempty"`
		PartitionLayout    string `json:"partition_layout,omitempty"`
		ConfigImage        string `json:"config_image,omitempty"`
	} `json:"layout"`
	RootfsDevice string `json:"rootfs_device,omitempty"`

	// [consumed] integrity map (path relative to root → sha256/size). Thor v1
	// lists stage 1; T234 v2 lists every staged file, including partition images.
	Files map[string]FileMeta `json:"files"`

	// [provenance] recorded for humans; not read by code.
	Board         string `json:"board"`
	Machine       string `json:"machine"`
	Chip          string `json:"chip"`
	Ramcode       string `json:"ramcode"`
	ChipSKU       string `json:"chip_sku"`
	PyYAMLVersion string `json:"pyyaml_version"`
}

// Flashpack is an opened, extracted flashpack on disk.
type Flashpack struct {
	Root     string
	Manifest Manifest
}

// Stage1Dir holds the RCM-boot images the bringup stage sends verbatim.
func (f *Flashpack) Stage1Dir() string {
	return filepath.Join(f.Root, f.Manifest.Layout.Stage1)
}

// FlashWorkspaceDir is the bootburn -P workspace (contains flash-images/).
func (f *Flashpack) FlashWorkspaceDir() string {
	return filepath.Join(f.Root, f.Manifest.Layout.FlashWorkspace)
}

// WorkspaceOutDir is the generated "out" dir (flash_workspace/ + sibling tools/);
// bootburn reads flash_workspace/../tools, so the sibling layout must be preserved.
func (f *Flashpack) WorkspaceOutDir() string {
	return filepath.Dir(f.FlashWorkspaceDir())
}

// BundleDir holds NVIDIA's bootburn scripts. The path is fixed by the flashpack
// layout the builder produces (stage2/bundle), so it is not a manifest field.
func (f *Flashpack) BundleDir() string {
	return filepath.Join(f.Root, "stage2", "bundle")
}

// PyYAMLDir holds the pure-python PyYAML package (a yaml/ dir + LICENSE) that
// bootburn imports; the host adds it to PYTHONPATH at flash time. Fixed by the
// flashpack layout (stage2/pyyaml), so it is not a manifest field.
func (f *Flashpack) PyYAMLDir() string {
	return filepath.Join(f.Root, "stage2", "pyyaml")
}

func (f *Flashpack) IsT234() bool { return f.Manifest.Family == FamilyT234 }

func (f *Flashpack) FlashPackageImage() string {
	return filepath.Join(f.Root, filepath.FromSlash(f.Manifest.Layout.FlashPackageImage))
}

func (f *Flashpack) FlashImagesDir() string {
	return filepath.Join(f.Root, filepath.FromSlash(f.Manifest.Layout.FlashImages))
}

func (f *Flashpack) PartitionLayout() string {
	return filepath.Join(f.Root, filepath.FromSlash(f.Manifest.Layout.PartitionLayout))
}

func (f *Flashpack) ConfigImage() string {
	return filepath.Join(f.Root, filepath.FromSlash(f.Manifest.Layout.ConfigImage))
}

// MemBCT is the membct filename to send in stage 1 (selected by on-board RAMCODE/2
// on the builder; all variants are shipped under stage1/).
func (f *Flashpack) MemBCT() string { return f.Manifest.DefaultMemBCT }

// FlashpackName is the cache basename for a given version (without extension).
func FlashpackName(version string) string {
	return "jetson-agx-thor-" + version + ".flashpack"
}

// TarballCachePath is where a downloaded/planted flashpack tarball for version lives.
func TarballCachePath(cacheDir, version string) string {
	return filepath.Join(cacheDir, FlashpackName(version)+".tar.zst")
}

// RecoveryRef identifies one storage-scoped recovery artifact.
type RecoveryRef struct {
	Device  string
	Storage string
	Version string
}

func (r RecoveryRef) cacheBase() string {
	return fmt.Sprintf("%s-%s-%s.flashpack", r.Device, r.Storage, r.Version)
}

func RecoveryTarballCachePath(cacheDir string, ref RecoveryRef) string {
	return filepath.Join(cacheDir, ref.cacheBase()+".tar.zst")
}

func RecoveryExtractedCachePath(cacheDir string, ref RecoveryRef) string {
	return filepath.Join(cacheDir, ref.cacheBase())
}

// Resolve returns the flashpack for version, cache-first: an already-extracted tree,
// else a planted/downloaded .tar.zst extracted on demand (atomically). The stage-1
// files are integrity-checked against the manifest before the flashpack is returned,
// so a corrupt cache aborts the flash rather than producing an opaque bootROM
// failure. Returns ErrNotInCache when nothing is present for the caller to download.
func Resolve(cacheDir, version string) (*Flashpack, error) {
	if version == "" {
		return nil, fmt.Errorf("a version is required to resolve a Thor flashpack")
	}
	return resolvePaths(filepath.Join(cacheDir, FlashpackName(version)), TarballCachePath(cacheDir, version), version)
}

// ResolveRecovery resolves a storage-scoped T234 flashpack and rejects any
// artifact whose signed manifest target does not match the requested route.
func ResolveRecovery(cacheDir string, ref RecoveryRef) (*Flashpack, error) {
	if ref.Device == "" || ref.Storage == "" || ref.Version == "" {
		return nil, fmt.Errorf("device, storage, and version are required to resolve a recovery flashpack")
	}
	fp, err := resolvePaths(filepath.Join(cacheDir, ref.cacheBase()), RecoveryTarballCachePath(cacheDir, ref), ref.Version)
	if err != nil {
		return nil, err
	}
	if !fp.IsT234() || fp.Manifest.Target.Device != ref.Device || fp.Manifest.Target.Storage != ref.Storage {
		return nil, fmt.Errorf("flashpack target is %s/%s, requested %s/%s", fp.Manifest.Target.Device, fp.Manifest.Target.Storage, ref.Device, ref.Storage)
	}
	if fp.Manifest.WendyOSVersion != ref.Version {
		return nil, fmt.Errorf("flashpack WendyOS version is %q, requested %q", fp.Manifest.WendyOSVersion, ref.Version)
	}
	return fp, nil
}

func resolvePaths(extracted, tarball, version string) (*Flashpack, error) {
	var extractedErr error
	if fp, err := open(extracted); err == nil {
		return fp, fp.verifyIntegrity()
	} else if _, statErr := os.Stat(extracted); statErr == nil {
		extractedErr = err
	}
	if _, err := os.Stat(tarball); err == nil {
		if err := extractZstTar(tarball, extracted); err != nil {
			return nil, fmt.Errorf("extracting %s: %w", filepath.Base(tarball), err)
		}
		fp, err := open(extracted)
		if err != nil {
			return nil, err
		}
		return fp, fp.verifyIntegrity()
	}
	if extractedErr != nil {
		return nil, fmt.Errorf("opening extracted flashpack: %w", extractedErr)
	}
	return nil, fmt.Errorf("%w: version %s", ErrNotInCache, version)
}

func open(root string) (*Flashpack, error) {
	data, err := os.ReadFile(filepath.Join(root, "manifest.json"))
	if err != nil {
		return nil, err
	}
	var m Manifest
	if err := json.Unmarshal(data, &m); err != nil {
		return nil, fmt.Errorf("parsing manifest.json: %w", err)
	}
	if err := validateManifest(&m); err != nil {
		return nil, err
	}
	return &Flashpack{Root: root, Manifest: m}, nil
}

func validateManifest(m *Manifest) error {
	if m.Family == FamilyT234 {
		if m.Schema != T234Schema {
			return fmt.Errorf("T234 flashpack schema %d is unsafe/unsupported (want %d); obtain a schema-v2 recovery artifact", m.Schema, T234Schema)
		}
		if m.Protocol != T234ProtocolMassStorage {
			return fmt.Errorf("T234 flashpack protocol %q is unsupported", m.Protocol)
		}
		if m.USBProductID != "0x7023" {
			return fmt.Errorf("T234 flashpack has unexpected USB product %q", m.USBProductID)
		}
		if err := validateT234Target(m); err != nil {
			return err
		}
		if len(m.RCMPhases) != 2 || m.RootfsDevice == "" || m.Layout.Stage1 == "" || m.Layout.FlashPackageImage == "" || m.Layout.FlashPackageStatus == "" || m.Layout.FlashPackageLogs == "" || m.Layout.FlashImages == "" || m.Layout.PartitionLayout == "" || m.Layout.ConfigImage == "" {
			return fmt.Errorf("T234 flashpack manifest is missing a consumed protocol/layout field")
		}
		for _, rel := range []string{m.Layout.Stage1, m.Layout.FlashPackageImage, m.Layout.FlashImages, m.Layout.PartitionLayout, m.Layout.ConfigImage, m.Layout.FlashPackageStatus, m.Layout.FlashPackageLogs} {
			if !safeRelativePath(rel) {
				return fmt.Errorf("T234 flashpack contains unsafe consumed path %q", rel)
			}
		}
		if !pathWithin(m.Layout.FlashImages, m.Layout.PartitionLayout) || !pathWithin(m.Layout.FlashImages, m.Layout.ConfigImage) {
			return fmt.Errorf("T234 partition layout and config image must be inside flash_images")
		}
		for _, phase := range m.RCMPhases {
			if len(phase) == 0 {
				return fmt.Errorf("T234 flashpack contains an empty RCM phase")
			}
			for _, d := range phase {
				if d.Type == "" || d.File == "" {
					return fmt.Errorf("T234 flashpack contains an incomplete RCM download")
				}
				if !pathWithin(m.Layout.Stage1, d.File) {
					return fmt.Errorf("T234 RCM file %s is outside stage1", d.File)
				}
				if _, ok := m.Files[d.File]; !ok {
					return fmt.Errorf("T234 flashpack integrity map omits RCM file %s", d.File)
				}
			}
		}
		for _, rel := range []string{m.Layout.FlashPackageImage, m.Layout.PartitionLayout, m.Layout.ConfigImage} {
			if _, ok := m.Files[rel]; !ok {
				return fmt.Errorf("T234 flashpack integrity map omits required file %s", rel)
			}
		}
		if m.Files[m.Layout.FlashPackageImage].Size != t234FlashPackageSize {
			return fmt.Errorf("T234 flash package is %d bytes (want %d)", m.Files[m.Layout.FlashPackageImage].Size, t234FlashPackageSize)
		}
		return nil
	}
	// Continue accepting exactly the existing untagged Thor v1 contract.
	if m.Family != "" || m.Schema != 1 {
		if m.Schema > SupportedSchema {
			return fmt.Errorf("flashpack schema %d is newer than this wendy supports (%d); update wendy", m.Schema, SupportedSchema)
		}
		return fmt.Errorf("unsupported flashpack family %q schema %d", m.Family, m.Schema)
	}
	if m.Layout.Stage1 == "" || m.Layout.FlashWorkspace == "" {
		return fmt.Errorf("Thor flashpack manifest missing layout")
	}
	return nil
}

func validateT234Target(m *Manifest) error {
	type targetSpec struct {
		moduleID, moduleSKU, carrierID, carrierSKU, rootfsDevice string
	}
	supported := map[string]targetSpec{
		"jetson-orin-nano/nvme": {"3767", "0005", "3768", "0000", "nvme0n1"},
		"jetson-agx-orin/nvme":  {"3701", "0005", "3737", "0000", "nvme0n1"},
		"jetson-agx-orin/emmc":  {"3701", "0005", "3737", "0000", "mmcblk0"},
	}
	key := m.Target.Device + "/" + m.Target.Storage
	want, ok := supported[key]
	if !ok {
		return fmt.Errorf("T234 flashpack target %q is unsupported", key)
	}
	got := m.Target
	if got.ModuleID != want.moduleID || got.ModuleSKU != want.moduleSKU || got.CarrierID != want.carrierID || got.CarrierSKU != want.carrierSKU || m.RootfsDevice != want.rootfsDevice {
		return fmt.Errorf("T234 flashpack target %s has unsupported identity/rootfs mapping", key)
	}
	return nil
}

func safeRelativePath(rel string) bool {
	clean := filepath.Clean(filepath.FromSlash(rel))
	return clean != "." && !filepath.IsAbs(clean) && clean != ".." && !strings.HasPrefix(clean, ".."+string(os.PathSeparator))
}

func pathWithin(parent, child string) bool {
	parent = filepath.Clean(filepath.FromSlash(parent))
	child = filepath.Clean(filepath.FromSlash(child))
	rel, err := filepath.Rel(parent, child)
	return err == nil && rel != "." && rel != ".." && !strings.HasPrefix(rel, ".."+string(os.PathSeparator))
}

// verifyIntegrity checks every declared file against its recorded size, and its
// SHA-256 for the small consumed control set: stage 1, the command package, the
// partition layout, and the config image. The large T234 partition images —
// dominated by the multi-GiB rootfs — are size-checked only. They are already
// covered by the download-time tarball checksum and the atomic extraction, so
// re-hashing them on every resolve (including cache hits) costs seconds of IO
// per install for no added guarantee; Thor never hashes its stage-2 images at
// all. Every staged image must still appear in the map, and no stray file may
// live under the flash-images tree (checked below).
func (f *Flashpack) verifyIntegrity() error {
	for rel, meta := range f.Manifest.Files {
		clean := filepath.Clean(filepath.FromSlash(rel))
		if clean == "." || filepath.IsAbs(clean) || clean == ".." || strings.HasPrefix(clean, ".."+string(os.PathSeparator)) {
			return fmt.Errorf("flashpack manifest contains unsafe path %q", rel)
		}
		p := filepath.Join(f.Root, clean)
		info, err := os.Lstat(p)
		if err != nil {
			return fmt.Errorf("flashpack missing %s: %w; %s", rel, err, clearCacheHint)
		}
		if !info.Mode().IsRegular() {
			return fmt.Errorf("flashpack %s is not a regular file; %s", rel, clearCacheHint)
		}
		if info.Size() != meta.Size {
			return fmt.Errorf("flashpack %s wrong size (got %d, want %d); %s", rel, info.Size(), meta.Size, clearCacheHint)
		}
		if f.sizeOnlyStagedImage(rel) {
			continue
		}
		sum, err := sha256File(p)
		if err != nil {
			return fmt.Errorf("hashing %s: %w", rel, err)
		}
		if !strings.EqualFold(sum, meta.SHA256) {
			return fmt.Errorf("flashpack %s checksum mismatch (got %s, want %s); %s", rel, sum, meta.SHA256, clearCacheHint)
		}
	}
	if f.IsT234() {
		imagesRoot := f.FlashImagesDir()
		if err := filepath.WalkDir(imagesRoot, func(path string, entry os.DirEntry, walkErr error) error {
			if walkErr != nil {
				return walkErr
			}
			if entry.IsDir() {
				return nil
			}
			info, err := entry.Info()
			if err != nil || !info.Mode().IsRegular() {
				return fmt.Errorf("flashpack image entry %s is not a regular file", path)
			}
			rel, err := filepath.Rel(f.Root, path)
			if err != nil {
				return err
			}
			rel = filepath.ToSlash(rel)
			if _, ok := f.Manifest.Files[rel]; !ok {
				return fmt.Errorf("T234 flashpack integrity map omits staged image %s", rel)
			}
			return nil
		}); err != nil {
			return fmt.Errorf("validating T234 flash images: %w; %s", err, clearCacheHint)
		}
	}
	return nil
}

// sizeOnlyStagedImage reports whether rel is a large T234 partition image that
// verifyIntegrity checks by size only. The consumed control files that live
// inside the flash-images tree — the partition layout and the config image —
// are excluded so they keep full-hash coverage; everything outside the tree
// (stage 1, the command package) is always fully hashed.
func (f *Flashpack) sizeOnlyStagedImage(rel string) bool {
	if !f.IsT234() {
		return false
	}
	if !pathWithin(f.Manifest.Layout.FlashImages, rel) {
		return false
	}
	key := toSlashClean(rel)
	return key != toSlashClean(f.Manifest.Layout.PartitionLayout) &&
		key != toSlashClean(f.Manifest.Layout.ConfigImage)
}

func toSlashClean(p string) string {
	return filepath.ToSlash(filepath.Clean(filepath.FromSlash(p)))
}

func sha256File(path string) (string, error) {
	f, err := os.Open(path)
	if err != nil {
		return "", err
	}
	defer f.Close()
	h := sha256.New()
	if _, err := io.Copy(h, f); err != nil {
		return "", err
	}
	return hex.EncodeToString(h.Sum(nil)), nil
}
